  ('generalpolice-94737317-moex-00582', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-b182839b', 'sub-generalpolice-94737317-05', NULL, 'single_choice', 'A公司之股東甲擬在股東會中提出議案，下列關於公司法第172條之1規定的少數股東提案權之敘 述，何者正確？', '["股東常會和股東臨時會均有少數股東提案權之適用", "甲至少須持股百分之三以上", "提案字數得超過300字", "提案係為敦促公司增進公共利益或善盡社會責任之建議，董事會仍得列入議案"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "dcc9138c5f9e", "answer_pdf_sha1": "09f272857164", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(中華民國憲法概要、法學緒論)", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
