  ('generalpolice-94737317-moex-00588', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '可燃性氣體在同一狀態下，下列熱源何者可造成最低之發火溫度？', '["全面加熱", "高溫固體", "加熱電阻線", "高溫氣體"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "3eaa6ffe1e08", "answer_pdf_sha1": "faf004e710c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00589', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '從管線洩漏之可燃性氣體，立即與周圍空氣混合而燃燒之現象為：', '["擴散燃燒", "混合燃燒", "蒸發燃燒", "分解燃燒"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "3eaa6ffe1e08", "answer_pdf_sha1": "faf004e710c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00590', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '地板上鋪設兩片材質不同但厚度、面積、密度、比熱以及點燃溫度均相同的厚木板，火災時同時 接受高溫煙層的輻射熱而先後點燃，假設兩片木板完全吸收輻射熱，而且地板與木板接觸面無熱 損失，則先被點燃的木板：', '["熱傳導率較大", "熱傳導率較小", "含碳量較大", "含碳量較小"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "3eaa6ffe1e08", "answer_pdf_sha1": "faf004e710c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00591', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '有一居室內設有小型會議室，該居室與內部小型會議室皆為單一出口，分別為2平方公尺及4平 方公尺的開口，二者開口前後串聯，其等效流動面積為多少平方公尺？（已知：√2=1.414； √3=1.732；√5=2.236；√6=2.449）', '["0.93", "1.79", "2.38", "3.15"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "3eaa6ffe1e08", "answer_pdf_sha1": "faf004e710c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
